#include <unistd.h>
#include <fcntl.h>
#include <stdio.h>

int main() {
 int fd;

 // Open a directory
 fd = open("/tmp", O_RDONLY | O_DIRECTORY);
 if (fd < 0) {
 perror("open");
 return 1;
 }

 // Change to that directory using file descriptor
 if (fchdir(fd) < 0) {
 perror("fchdir");
 close(fd);
 return 1;
 }

 printf("Changed to /tmp using fchdir\n");
 close(fd);
 return 0;
}

#include <unistd.h>
#include <stdio.h>
#include <limits.h>

int main() {
 char cwd[PATH_MAX];

 if (getcwd(cwd, sizeof(cwd)) != NULL) {
 printf("Current working directory: %s\n", cwd);
 } else {
 perror("getcwd");
 return 1;
 }

 return 0;
}

#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>

int main() {
 dev_t dev;

 // Create device number: major=8, minor=0
 dev = makedev(8, 0);

 // Create block device file /tmp/mydevice
 if (mknod("/tmp/mydevice", S_IFBLK | 0660, dev) < 0) {
 perror("mknod");
 return 1;
 }

 printf("Block device created\n");
 return 0;
}

#include <sys/types.h>
#include <sys/stat.h>
#include <stdio.h>

int main(const char *filepath) {
 struct stat st;

 if (stat(filepath, &st) < 0) {
 perror("stat");
 return 1;
 }

 // Check if it's a device
 if (S_ISBLK(st.st_mode)) {
 printf("Block device: major=%d, minor=%d\n",
 major(st.st_rdev), minor(st.st_rdev));
 } else if (S_ISCHR(st.st_mode)) {
 printf("Character device: major=%d, minor=%d\n",
 major(st.st_rdev), minor(st.st_rdev));
 } else {
 printf("Not a device file\n");
 }

 return 0;
}
